import React, { useState } from 'react';
import { useApp } from '../../context/AppContext';
import { today, getLast30Days, formatDate, calcBMI, getBMICategory } from '../../utils/helpers';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer, ReferenceLine, CartesianGrid } from 'recharts';

const CustomTooltip = ({ active, payload, label }) => {
  if (active && payload && payload.length) {
    return (
      <div style={{ background: '#161d2e', border: '1px solid rgba(255,123,53,0.2)', borderRadius: 10, padding: '8px 14px' }}>
        <div style={{ fontSize: 11, color: '#8892aa' }}>{label}</div>
        <div style={{ fontFamily: 'var(--font-display)', fontWeight: 700, color: '#ff7b35', fontSize: 18 }}>
          {payload[0].value}kg
        </div>
      </div>
    );
  }
  return null;
};

const BMI_ZONES = [
  { label: 'Thiếu cân', range: '< 18.5', color: '#00d4ff' },
  { label: 'Bình thường', range: '18.5 – 23', color: '#00e5a0' },
  { label: 'Thừa cân', range: '23 – 27.5', color: '#ff7b35' },
  { label: 'Béo phì', range: '≥ 27.5', color: '#ff4f8b' },
];

export default function WeightTracker() {
  const { state, dispatch } = useApp();
  const todayStr = today();
  const profile = state.profile;
  const [inputVal, setInputVal] = useState('');
  const [saved, setSaved] = useState(false);
  const [period, setPeriod] = useState('month');

  const days = getLast30Days();
  const weightData = days.map(d => ({
    date: formatDate(d),
    weight: state.weight.find(w => w.date === d)?.value || null,
  })).filter(d => d.weight !== null);

  const latestWeight = state.weight.length > 0 ? state.weight[state.weight.length - 1].value : profile?.weight || null;
  const firstWeight = state.weight.length > 0 ? state.weight[0].value : null;
  const change = firstWeight && latestWeight ? (latestWeight - firstWeight).toFixed(1) : null;
  const bmi = calcBMI(latestWeight, profile?.height);
  const bmiCat = getBMICategory(bmi);

  const handleSave = () => {
    if (!inputVal || isNaN(+inputVal) || +inputVal <= 0) return;
    dispatch({ type: 'ADD_WEIGHT', payload: +inputVal });
    setInputVal('');
    setSaved(true);
    setTimeout(() => setSaved(false), 2000);
  };

  const idealWeightMin = profile?.height ? ((profile.height / 100) ** 2 * 18.5).toFixed(1) : null;
  const idealWeightMax = profile?.height ? ((profile.height / 100) ** 2 * 23).toFixed(1) : null;

  return (
    <div>
      <div style={styles.header}>
        <div>
          <div style={styles.title}>⚖️ Cân nặng</div>
          <div style={styles.sub}>Theo dõi cân nặng và chỉ số BMI</div>
        </div>
        {bmiCat && (
          <div style={{ ...styles.bmiPill, background: `${bmiCat.color}18`, border: `1px solid ${bmiCat.color}40`, color: bmiCat.color }}>
            BMI {bmi} · {bmiCat.label}
          </div>
        )}
      </div>

      {/* Stat row */}
      <div className="grid-4" style={{ marginBottom: 20 }}>
        <div className="card" style={{ borderLeft: '3px solid #ff7b35' }}>
          <div style={styles.statNum}>{latestWeight || '--'}<span style={styles.statUnit}>kg</span></div>
          <div style={styles.statLabel}>Cân nặng hiện tại</div>
        </div>
        <div className="card" style={{ borderLeft: `3px solid ${bmiCat?.color || '#a855f7'}` }}>
          <div style={{ ...styles.statNum, color: bmiCat?.color || '#a855f7' }}>{bmi || '--'}</div>
          <div style={styles.statLabel}>{bmiCat?.label || 'BMI'}</div>
        </div>
        <div className="card" style={{ borderLeft: `3px solid ${change >= 0 ? '#ff7b35' : '#00e5a0'}` }}>
          <div style={{ ...styles.statNum, color: change >= 0 ? '#ff7b35' : '#00e5a0' }}>
            {change !== null ? (change >= 0 ? `+${change}` : change) : '--'}<span style={styles.statUnit}>kg</span>
          </div>
          <div style={styles.statLabel}>Thay đổi</div>
        </div>
        <div className="card" style={{ borderLeft: '3px solid #00e5a0' }}>
          <div style={styles.statNum}>{idealWeightMin ? `${idealWeightMin}–${idealWeightMax}` : '--'}<span style={styles.statUnit}>kg</span></div>
          <div style={styles.statLabel}>Cân nặng lý tưởng</div>
        </div>
      </div>

      {/* Main content */}
      <div style={styles.mainRow}>
        {/* Chart */}
        <div className="card" style={{ flex: 2 }}>
          <div style={styles.chartHeader}>
            <div style={styles.sectionTitle}>Biểu đồ cân nặng</div>
            <div style={{ display: 'flex', gap: 8 }}>
              {['month'].map(p => (
                <button key={p} className="btn btn-primary btn-sm">{p === 'month' ? '30 ngày' : '7 ngày'}</button>
              ))}
            </div>
          </div>

          {weightData.length < 2 ? (
            <div style={styles.emptyState}>
              <span style={{ fontSize: 40 }}>📊</span>
              <div>Cần ít nhất 2 dữ liệu để vẽ biểu đồ</div>
            </div>
          ) : (
            <ResponsiveContainer width="100%" height={220}>
              <LineChart data={weightData}>
                <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" />
                <XAxis dataKey="date" tick={{ fill: '#8892aa', fontSize: 11 }} axisLine={false} tickLine={false} interval={4} />
                <YAxis
                  tick={{ fill: '#8892aa', fontSize: 11 }}
                  axisLine={false}
                  tickLine={false}
                  domain={['dataMin - 2', 'dataMax + 2']}
                />
                <Tooltip content={<CustomTooltip />} />
                {idealWeightMin && <ReferenceLine y={+idealWeightMin} stroke="rgba(0,229,160,0.3)" strokeDasharray="4 4" label={{ value: 'Min ideal', fill: '#00e5a0', fontSize: 10 }} />}
                {idealWeightMax && <ReferenceLine y={+idealWeightMax} stroke="rgba(0,229,160,0.3)" strokeDasharray="4 4" label={{ value: 'Max ideal', fill: '#00e5a0', fontSize: 10 }} />}
                <Line
                  type="monotone" dataKey="weight" stroke="#ff7b35"
                  strokeWidth={2.5} dot={{ fill: '#ff7b35', r: 3 }}
                  activeDot={{ r: 6, fill: '#ff7b35', stroke: '#fff', strokeWidth: 2 }}
                  connectNulls
                />
              </LineChart>
            </ResponsiveContainer>
          )}

          {idealWeightMin && (
            <div style={{ display: 'flex', gap: 16, marginTop: 8, flexWrap: 'wrap' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 11, color: '#8892aa' }}>
                <div style={{ width: 20, height: 2, borderTop: '2px dashed rgba(0,229,160,0.5)' }} />
                Vùng lý tưởng ({idealWeightMin}–{idealWeightMax}kg)
              </div>
            </div>
          )}
        </div>

        {/* Right column */}
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: 16 }}>
          {/* Input */}
          <div className="card">
            <div style={styles.sectionTitle}>Cập nhật cân nặng</div>
            <div className="input-group" style={{ marginBottom: 12 }}>
              <label className="input-label">Cân nặng (kg)</label>
              <input
                type="number"
                step="0.1"
                className="input-field"
                placeholder="68.5"
                value={inputVal}
                onChange={e => setInputVal(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleSave()}
              />
            </div>
            <button className="btn btn-primary" style={{ width: '100%' }} onClick={handleSave} disabled={!inputVal}>
              {saved ? '✓ Đã lưu' : '💾 Lưu cân nặng'}
            </button>
          </div>

          {/* BMI scale */}
          <div className="card">
            <div style={styles.sectionTitle}>Phân loại BMI</div>
            {BMI_ZONES.map(z => (
              <div key={z.label} style={{
                ...styles.bmiZone,
                background: bmiCat?.label === z.label ? `${z.color}12` : 'transparent',
                border: `1px solid ${bmiCat?.label === z.label ? z.color + '40' : 'transparent'}`,
              }}>
                <div style={{ width: 10, height: 10, borderRadius: '50%', background: z.color, flexShrink: 0 }} />
                <div style={styles.bmiZoneLabel}>{z.label}</div>
                <div style={{ fontSize: 12, color: '#4a5568', marginLeft: 'auto' }}>{z.range}</div>
                {bmiCat?.label === z.label && <span style={{ fontSize: 12, marginLeft: 8 }}>◀</span>}
              </div>
            ))}
          </div>

          {/* History */}
          <div className="card">
            <div style={styles.sectionTitle}>Gần đây</div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              {state.weight.slice(-5).reverse().map((w, i) => (
                <div key={i} style={styles.histItem}>
                  <span style={{ fontSize: 14 }}>⚖️</span>
                  <span style={{ fontFamily: 'var(--font-display)', fontWeight: 700, color: '#ff7b35', fontSize: 15 }}>{w.value}kg</span>
                  <span style={{ fontSize: 11, color: '#8892aa', marginLeft: 'auto' }}>{formatDate(w.date)}</span>
                </div>
              ))}
              {state.weight.length === 0 && <div style={{ fontSize: 13, color: '#4a5568' }}>Chưa có dữ liệu</div>}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

const styles = {
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 28, flexWrap: 'wrap', gap: 12 },
  title: { fontFamily: 'var(--font-display)', fontSize: 28, fontWeight: 800, color: '#f0f4ff', marginBottom: 4 },
  sub: { fontSize: 14, color: '#8892aa' },
  bmiPill: { padding: '8px 16px', borderRadius: 20, fontFamily: 'var(--font-display)', fontWeight: 700, fontSize: 14 },
  statNum: { fontFamily: 'var(--font-display)', fontSize: 24, fontWeight: 800, color: '#f0f4ff', marginBottom: 4 },
  statUnit: { fontSize: 12, fontWeight: 500, color: '#8892aa', marginLeft: 4 },
  statLabel: { fontSize: 12, color: '#8892aa' },
  mainRow: { display: 'flex', gap: 20, flexWrap: 'wrap' },
  chartHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 },
  sectionTitle: { fontFamily: 'var(--font-display)', fontWeight: 700, fontSize: 15, color: '#f0f4ff', marginBottom: 14 },
  emptyState: { height: 200, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: 12, color: '#4a5568', fontSize: 13 },
  bmiZone: { display: 'flex', alignItems: 'center', gap: 10, padding: '8px 10px', borderRadius: 8, marginBottom: 6, transition: 'all 0.2s ease' },
  bmiZoneLabel: { fontSize: 13, color: '#8892aa', fontWeight: 500 },
  histItem: { display: 'flex', alignItems: 'center', gap: 10, padding: '7px 10px', background: 'rgba(255,255,255,0.02)', borderRadius: 8 },
};
